function lower(v){return String(v??'').toLowerCase()}
function getSettings(){return Object.assign({enabled:true,autoRunOnOpen:true,notifyInsideCRM:true,defaultReturnDays:1,stuckDays:5,noAnswerLimit:3,dailySummaryHour:'09:00'},readJSON(SETTINGS_KEY,{}))}
function saveSettings(s){writeJSON(SETTINGS_KEY,Object.assign(getSettings(),s||{}))}
function seedLeads(){return [
 {id:'lead_demo_barbearia',empresa:'Barbearia Alfa',nome:'Barbearia Alfa',telefone:'51999990001',cidade:'Porto Alegre',segmento:'Barbearia',origem:'Garimpo',campanha:'Barbearias POA',prioridade:'Alta',pipelineStage:'Lead',followupStage:'Primeiro contato',nextAction:'Ligar hoje',proximaData:today(),attempts:0,noAnswerAttempts:0,tags:['Garimpo'],history:[]},
 {id:'lead_demo_clinica',empresa:'Clínica Bella',nome:'Clínica Bella',telefone:'51999990002',cidade:'Canoas',segmento:'Estética',origem:'Indicação',campanha:'Prospecção local',prioridade:'Média',pipelineStage:'Proposta',followupStage:'Aguardando resposta',nextAction:'Follow-up de proposta',proximaData:addDays(-1),attempts:2,noAnswerAttempts:1,tags:['Proposta'],history:[]},
 {id:'lead_demo_studio',empresa:'Studio Prime',nome:'Studio Prime',telefone:'',cidade:'Gravataí',segmento:'Beleza',origem:'Garimpo',campanha:'Sem telefone',prioridade:'Baixa',pipelineStage:'Lead',followupStage:'Dados incompletos',nextAction:'',proximaData:'',attempts:0,noAnswerAttempts:0,tags:['Incompleto'],history:[]}
]}
function findLeadKey(){for(const k of LEAD_KEYS){const v=readJSON(k,null);if(Array.isArray(v))return k}return LEAD_KEYS[0]}
function getLeads(){let key=findLeadKey();let leads=readJSON(key,null);if(!Array.isArray(leads)||!leads.length){leads=seedLeads();writeJSON(key,leads)}let touched=false;leads=leads.map((l,i)=>{const lead=Object.assign({},l);if(!lead.id){lead.id=uid('lead');touched=true}if(!lead.history)lead.history=[];if(!Array.isArray(lead.tags))lead.tags=lead.tags?[String(lead.tags)]:[];return lead});if(touched)writeJSON(key,leads);return {key,leads}}
function setLeads(key,leads){writeJSON(key,leads)}
function leadName(lead){return lead.empresa||lead.nome||lead.name||lead.company||'Lead sem nome'}
function phone(lead){return lead.telefone||lead.phone||lead.whatsapp||''}
function getField(lead,field){
 if(field==='origin')return lead.origem||lead.origin||'';
 if(field==='city')return lead.cidade||lead.city||'';
 if(field==='segment')return lead.segmento||lead.segment||'';
 if(field==='priority')return lead.prioridade||lead.priority||'';
 if(field==='pipelineStage')return lead.pipelineStage||lead.pipeline||lead.etapaPipeline||lead.stage||'';
 if(field==='followupStage')return lead.followupStage||lead.followup||lead.etapaFollowup||'';
 if(field==='attempts')return Number(lead.attempts||lead.contatos||lead.totalContatos||0);
 if(field==='noAnswerAttempts')return Number(lead.noAnswerAttempts||lead.semResposta||0);
 if(field==='hasPhone')return !!phone(lead);
 if(field==='nextActionEmpty')return !(lead.nextAction||lead.proximaAcao||lead.proximaData||lead.nextDate);
 if(field==='daysWithoutContact')return daysWithoutContact(lead);
 if(field==='tag')return asArray(lead.tags).join(',');
 return lead[field];
}
function dateValue(v){if(!v)return null;const d=new Date(v);return isNaN(d.getTime())?null:d}
function daysWithoutContact(lead){const dates=[];asArray(lead.history).forEach(h=>{if(h.date||h.createdAt||h.at)dates.push(dateValue(h.date||h.createdAt||h.at))});if(lead.lastContactAt)dates.push(dateValue(lead.lastContactAt));const valid=dates.filter(Boolean).sort((a,b)=>b-a);if(!valid.length)return 999;return Math.floor((new Date()-valid[0])/(86400000))}
function isOverdue(lead){const d=dateValue(lead.proximaData||lead.nextDate||lead.followupDate);if(!d)return false;const t=new Date(today()+'T23:59:59');return d<t}
function isStuck(lead){return daysWithoutContact(lead)>=Number(getSettings().stuckDays||5)}
function matchCondition(lead,c){if(!c||!c.field)return true;const actual=getField(lead,c.field);const op=c.op||'equals';const value=c.value;
 if(op==='exists')return actual!==undefined&&actual!==null&&String(actual).trim()!=='';
 if(op==='empty')return actual===undefined||actual===null||String(actual).trim()===''||actual===false;
 if(op==='equals')return lower(actual)===lower(value);
 if(op==='not_equals')return lower(actual)!==lower(value);
 if(op==='contains')return lower(actual).includes(lower(value));
 if(op==='not_contains')return !lower(actual).includes(lower(value));
 if(op==='greater_than')return Number(actual)>Number(value);
 if(op==='less_than')return Number(actual)<Number(value);
 if(op==='is_true')return !!actual;
 if(op==='is_false')return !actual;
 return true}
function matchRuleLead(rule,lead){return asArray(rule.conditions).every(c=>matchCondition(lead,c))}
function defaultRules(){return [
 {id:'tpl_garimpo_primeira_ligacao',name:'Lead novo do Garimpo',desc:'Quando um lead vier do Garimpo com telefone, cria ligação para hoje e prepara o primeiro contato.',category:'Captar',favorite:true,active:true,trigger:'lead_saved_from_garimpo',conditions:[{field:'origin',op:'contains',value:'Garimpo'},{field:'hasPhone',op:'is_true',value:'true'}],actions:[{type:'create_call_today',value:'Primeira ligação'},{type:'move_followup_stage',value:'Primeiro contato'},{type:'add_tag',value:'Garimpo'},{type:'suggest_playbook',value:'Primeiro contato — Garimpo'},{type:'create_notification',value:'Novo lead do Garimpo pronto para ligar'}],runs:0,affected:0},
 {id:'tpl_nao_atendeu',name:'Não atendeu',desc:'Ao registrar ligação sem resposta, soma tentativa, cria retorno e coloca no Follow-up correto.',category:'Contatar',favorite:true,active:true,trigger:'call_result_no_answer',conditions:[],actions:[{type:'create_followup_tomorrow',value:'Tentar novamente'},{type:'move_followup_stage',value:'Sem resposta'},{type:'add_history_event',value:'Ligação registrada como não atendida'},{type:'create_notification',value:'Retorno criado para amanhã'}],runs:0,affected:0},
 {id:'tpl_tres_tentativas',name:'3 tentativas sem resposta',desc:'Quando um lead acumular 3 tentativas sem resposta, move para Reativação e sugere última tentativa.',category:'Recuperar',favorite:false,active:true,trigger:'lead_updated',conditions:[{field:'noAnswerAttempts',op:'greater_than',value:'2'}],actions:[{type:'move_followup_stage',value:'Reativação'},{type:'set_priority',value:'Média'},{type:'suggest_playbook',value:'Última tentativa / Reativação'},{type:'create_notification',value:'Lead movido para reativação'}],runs:0,affected:0},
 {id:'tpl_proposta_followup',name:'Proposta enviada',desc:'Quando o Pipeline entrar em Proposta, agenda follow-up e sugere script de acompanhamento.',category:'Avançar',favorite:true,active:true,trigger:'pipeline_changed_to_proposal',conditions:[],actions:[{type:'move_followup_stage',value:'Aguardando resposta'},{type:'create_agenda_task',value:'Follow-up de proposta em 2 dias'},{type:'suggest_playbook',value:'Follow-up de proposta'},{type:'add_tag',value:'Proposta aberta'}],runs:0,affected:0},
 {id:'tpl_sem_acao',name:'Lead sem próxima ação',desc:'Ao detectar lead solto, cria lembrete interno para não deixar a oportunidade morrer.',category:'Lembrar',favorite:true,active:true,trigger:'lead_without_next_action',conditions:[{field:'nextActionEmpty',op:'is_true',value:'true'}],actions:[{type:'create_followup_tomorrow',value:'Definir próximo contato'},{type:'mark_at_risk',value:'Sem próxima ação'},{type:'create_notification',value:'Lead estava sem próxima ação'}],runs:0,affected:0},
 {id:'tpl_followup_vencido',name:'Follow-up vencido',desc:'Quando um retorno vence, cria aviso interno e coloca o lead em risco.',category:'Lembrar',favorite:false,active:true,trigger:'followup_overdue',conditions:[],actions:[{type:'mark_at_risk',value:'Follow-up vencido'},{type:'create_notification',value:'Follow-up vencido precisa de ação'},{type:'add_history_event',value:'Automação detectou follow-up vencido'}],runs:0,affected:0},
 {id:'tpl_fechado',name:'Venda fechada',desc:'Quando o lead for fechado, encerra follow-up e registra conversão.',category:'Medir',favorite:false,active:true,trigger:'pipeline_won',conditions:[],actions:[{type:'close_followup',value:'Pós-venda'},{type:'add_history_event',value:'Conversão registrada automaticamente'},{type:'create_notification',value:'Venda fechada registrada'}],runs:0,affected:0},
 {id:'tpl_perdido',name:'Lead perdido',desc:'Quando mover para Perdido, pede motivo da perda e alimenta Métricas.',category:'Medir',favorite:false,active:true,trigger:'pipeline_lost',conditions:[],actions:[{type:'require_loss_reason',value:'Motivo obrigatório'},{type:'close_followup',value:'Encerrado'},{type:'add_history_event',value:'Lead perdido — motivo pendente'}],runs:0,affected:0}
]}
function getRules(){let rules=readJSON(RULE_KEY,null);if(!Array.isArray(rules)){for(const old of OLD_RULE_KEYS){const maybe=readJSON(old,null);if(Array.isArray(maybe)){rules=maybe;break}}}if(!Array.isArray(rules)||!rules.length){rules=defaultRules();writeJSON(RULE_KEY,rules)}rules=rules.map(r=>Object.assign({id:uid('rule'),name:'Regra sem nome',category:'Contatar',active:false,trigger:'manual_run',conditions:[],actions:[],runs:0,affected:0,createdAt:nowISO()},r));return rules}
function saveRules(rules){writeJSON(RULE_KEY,rules)}
function getHistory(){return readJSON(HIST_KEY,[])}
function saveHistory(h){writeJSON(HIST_KEY,h.slice(0,160))}
function addHistory(entry){const h=getHistory();h.unshift(Object.assign({id:uid('hist'),at:nowISO(),version:VERSION},entry));saveHistory(h)}
function addNotification(title,body,leadId){const n=readJSON(NOTIF_KEY,[]);n.unshift({id:uid('notif'),title,body,leadId,createdAt:nowISO(),read:false,source:'Automação V95.2'});writeJSON(NOTIF_KEY,n.slice(0,80))}
function saveUndo(key,leads,label){writeJSON(UNDO_KEY,{key,label,leads,createdAt:nowISO()})}
function applyAction(lead,action,eventType){const type=action.type;const val=action.value||'';let msg='';lead.history=asArray(lead.history);lead.tags=asArray(lead.tags);
 if(type==='create_call_today'){lead.nextAction=val||'Ligar hoje';lead.proximaData=today();lead.followupChannel='Ligação';msg='criou ligação para hoje'}
 if(type==='create_followup_tomorrow'){lead.nextAction=val||'Retorno';lead.proximaData=tomorrow();lead.followupChannel=lead.followupChannel||'Follow-up';msg='criou follow-up para amanhã'}
 if(type==='move_followup_stage'){lead.followupStage=val||'Sem resposta';lead.etapaFollowup=lead.followupStage;msg='moveu Follow-up para '+lead.followupStage}
 if(type==='move_pipeline_stage'){lead.pipelineStage=val||'Contato';lead.etapaPipeline=lead.pipelineStage;msg='moveu Pipeline para '+lead.pipelineStage}
 if(type==='add_tag'){if(val&&!lead.tags.includes(val))lead.tags.push(val);msg='aplicou tag '+val}
 if(type==='set_priority'){lead.prioridade=val||'Média';lead.priority=lead.prioridade;msg='alterou prioridade para '+lead.prioridade}
 if(type==='suggest_playbook'){lead.suggestedPlaybook=val||'Playbook sugerido';msg='sugeriu Playbook'}
 if(type==='create_agenda_task'){const agenda=readJSON(AGENDA_KEY,[]);if(Array.isArray(agenda)){agenda.unshift({id:uid('agenda'),leadId:lead.id,title:val||'Tarefa automática',date:val&&/2 dias/i.test(val)?addDays(2):(lead.proximaData||tomorrow()),createdAt:nowISO(),source:'Automação V95.2'});writeJSON(AGENDA_KEY,agenda.slice(0,200));msg='criou tarefa na Agenda'}}
 if(type==='mark_at_risk'){lead.risk=true;lead.riskReason=val||'Automação';msg='marcou como em risco'}
 if(type==='require_loss_reason'){lead.lossReasonRequired=true;lead.lossReason=lead.lossReason||'';msg='marcou motivo de perda como obrigatório'}
 if(type==='close_followup'){lead.followupStage=val||'Encerrado';lead.followupClosed=true;msg='encerrou Follow-up'}
 if(type==='add_history_event'){msg=val||'Evento automático registrado'}
 if(type==='create_notification'){addNotification(val||'Automação executada','Lead: '+leadName(lead),lead.id);msg='criou notificação interna'}
 if(eventType==='call_result_no_answer'){lead.attempts=Number(lead.attempts||lead.contatos||0)+1;lead.noAnswerAttempts=Number(lead.noAnswerAttempts||0)+1;lead.lastContactResult='Não atendeu';lead.lastContactAt=nowISO()}
 if(eventType==='call_result_answered'){lead.attempts=Number(lead.attempts||lead.contatos||0)+1;lead.noAnswerAttempts=0;lead.lastContactResult='Atendeu';lead.lastContactAt=nowISO()}
 if(eventType==='call_result_callback'){lead.attempts=Number(lead.attempts||lead.contatos||0)+1;lead.lastContactResult='Pediu retorno';lead.lastContactAt=nowISO()}
 if(type!=='create_notification')lead.history.unshift({id:uid('evt'),type:'automation',event:eventType,action:type,note:msg||label(actionLabels,type),date:nowISO(),source:'V95.2'});
 return msg||label(actionLabels,type)}
function eventCandidates(eventType,payload){const store=getLeads();let leads=store.leads;let candidates=[];if(payload&&payload.lead){const id=payload.lead.id;const idx=leads.findIndex(l=>l.id===id);if(idx>=0)candidates=[leads[idx]];else candidates=[Object.assign({},payload.lead)]}else if(payload&&payload.leadId){candidates=leads.filter(l=>l.id===payload.leadId)}else{
 candidates=leads.filter(l=>{
  if(eventType==='followup_overdue')return isOverdue(l);
  if(eventType==='lead_without_next_action')return getField(l,'nextActionEmpty');
  if(eventType==='lead_stuck')return isStuck(l);
  if(eventType==='lead_saved_from_garimpo')return lower(getField(l,'origin')).includes('garimpo');
  if(eventType==='pipeline_changed_to_proposal')return lower(getField(l,'pipelineStage')).includes('proposta');
  if(eventType==='pipeline_won')return lower(getField(l,'pipelineStage')).includes('fechado');
  if(eventType==='pipeline_lost')return lower(getField(l,'pipelineStage')).includes('perdido');
  return true;
 })
}
return {store,candidates}}
function runRule(rule,eventType,payload,opts){opts=opts||{};const {store,candidates}=eventCandidates(eventType,payload||{});const leads=store.leads.map(l=>Object.assign({},l));const before=JSON.parse(JSON.stringify(leads));let affected=0;let actionCount=0;let sample=[];const ids=new Set(candidates.map(l=>l.id));for(let i=0;i<leads.length;i++){
 const lead=leads[i];if(ids.size&&!ids.has(lead.id))continue;if(!matchRuleLead(rule,lead))continue;affected++;if(sample.length<5)sample.push(leadName(lead));if(!opts.test){for(const a of asArray(rule.actions)){applyAction(lead,a,eventType);actionCount++}}
}
if(!opts.test&&affected){saveUndo(store.key,before,'Execução da regra '+rule.name);setLeads(store.key,leads);const rules=getRules().map(r=>r.id===rule.id?Object.assign({},r,{runs:Number(r.runs||0)+1,affected:Number(r.affected||0)+affected,lastRunAt:nowISO()}):r);saveRules(rules)}
addHistory({kind:opts.test?'test':'execution',ruleId:rule.id,ruleName:rule.name,eventType,affected,actions:asArray(rule.actions).map(a=>a.type),sample,status:'success'});
return {affected,actionCount,sample,status:'success'}
}
function runMatchingRules(eventType,payload,opts){opts=opts||{};const settings=getSettings();if(!settings.enabled&&!opts.force)return {rules:0,affected:0,skipped:true};const rules=getRules().filter(r=>r.active!==false&&r.trigger===eventType);let total=0;let runs=[];for(const r of rules){const res=runRule(r,eventType,payload,opts);total+=res.affected;runs.push({rule:r.name,affected:res.affected})}if(rules.length)addHistory({kind:'event',eventType,affected:total,rules:rules.length,sample:runs.slice(0,4).map(x=>x.rule+': '+x.affected),status:'processed'});return {rules:rules.length,affected:total,runs}}
function emit(eventType,payload){const q=readJSON(EVENT_QUEUE_KEY,[]);q.unshift({id:uid('event'),eventType,payload:payload||{},at:nowISO()});writeJSON(EVENT_QUEUE_KEY,q.slice(0,80));return runMatchingRules(eventType,payload,{})}
function testRule(rule){return runRule(rule,rule.trigger||'manual_run',{}, {test:true,force:true})}
function undoLast(){const u=readJSON(UNDO_KEY,null);if(!u||!u.key||!Array.isArray(u.leads)){toast('Não encontrei execução para desfazer.');return false}writeJSON(u.key,u.leads);localStorage.removeItem(UNDO_KEY);addHistory({kind:'undo',eventType:'manual_run',affected:u.leads.length,ruleName:u.label||'Última execução',status:'undone'});toast('Última execução desfeita.');render();return true}
function runSystemChecks(){const settings=getSettings();if(!settings.autoRunOnOpen)return;runMatchingRules('followup_overdue',{},{});runMatchingRules('lead_without_next_action',{},{});runMatchingRules('lead_stuck',{},{});runMatchingRules('crm_opened',{},{});}
function stats(){const rules=getRules();const hist=getHistory();const leads=getLeads().leads;const todayStr=today();return {active:rules.filter(r=>r.active!==false).length,paused:rules.filter(r=>r.active===false).length,executedToday:hist.filter(h=>String(h.at||'').slice(0,10)===todayStr&&(h.kind==='execution'||h.kind==='event')).length,affectedToday:hist.filter(h=>String(h.at||'').slice(0,10)===todayStr).reduce((s,h)=>s+Number(h.affected||0),0),overdue:leads.filter(isOverdue).length,withoutNext:leads.filter(l=>getField(l,'nextActionEmpty')).length,notifications:readJSON(NOTIF_KEY,[]).filter(n=>!n.read).length}}
function toast(msg,small){let old=$('.v952-toast');if(old)old.remove();const t=D.createElement('div');t.className='v952-toast';t.innerHTML=esc(msg)+(small?'<small>'+esc(small)+'</small>':'');D.body.appendChild(t);setTimeout(()=>t.remove(),3600)}
function describeRule(rule){const trig=triggerLabels[rule.trigger]||rule.trigger||'evento manual';const conds=asArray(rule.conditions).filter(c=>c.field).map(c=>(fieldLabels[c.field]||c.field)+' '+(c.op||'é')+' '+(c.value||''));const acts=asArray(rule.actions).map(a=>actionLabels[a.type]||a.type);let text='Quando '+trig.toLowerCase();if(conds.length)text+=' e '+conds.join(' + ');if(acts.length)text+=', o CRM vai '+acts.join(', ').toLowerCase()+'.';return text}
function filteredRules(){const q=lower(searchTerm);return getRules().filter(r=>(activeCategory==='Todos'||r.category===activeCategory)&&(!q||lower(r.name+' '+r.desc+' '+r.category+' '+describeRule(r)).includes(q)))}
function layout(){const st=stats();return `<div class="v952-wrap">
<section class="v952-hero"><div><div class="v952-eyebrow">${VERSION} · Motor de regras interno</div><h1 class="v952-title">Automações que realmente mexem no CRM</h1><p class="v952-sub">Agora cada regra segue a lógica: evento, gatilho, condições, ações e histórico. As automações usam o mesmo lead ID e atualizam Leads, Ligações, Follow-up, Pipeline, Agenda, Playbooks e Métricas pelo localStorage.</p><div class="v952-hero-actions"><button class="v952-btn ghost" data-tab="recipes">Usar receita pronta</button><button class="v952-btn primary" data-new-rule>Criar regra</button><button class="v952-btn ghost" data-tab="engine">Ver motor interno</button><button class="v952-btn ghost" data-run-checks>Rodar verificações agora</button></div></div><div class="v952-engine-card"><div class="v952-engine-row"><span>Motor</span><b><span class="v952-dot"></span> Ativo</b></div><div class="v952-engine-row"><span>Execução</span><b>Dentro do CRM</b></div><div class="v952-engine-row"><span>Eventos monitorados</span><b>${Object.keys(triggerLabels).length}</b></div><div class="v952-engine-row"><span>Notificações internas</span><b>${st.notifications}</b></div></div></section>
<section class="v952-stats"><div class="v952-stat"><strong>${st.active}</strong><span>automações ativas</span></div><div class="v952-stat"><strong>${st.executedToday}</strong><span>eventos hoje</span></div><div class="v952-stat"><strong>${st.affectedToday}</strong><span>leads impactados hoje</span></div><div class="v952-stat"><strong>${st.overdue}</strong><span>follow-ups vencidos</span></div><div class="v952-stat"><strong>${st.withoutNext}</strong><span>sem próxima ação</span></div></section>
<nav class="v952-tabs">${['overview','recipes','rules','builder','engine','history','settings'].map(t=>`<button class="v952-tab ${activeTab===t?'active':''}" data-tab="${t}">${tabName(t)}</button>`).join('')}</nav>
${renderTab()}
</div>`}
function tabName(t){return {overview:'Visão geral',recipes:'Receitas prontas',rules:'Minhas automações',builder:'Criar regra',engine:'Motor interno',history:'Histórico',settings:'Configurações'}[t]||t}
function renderTab(){if(activeTab==='recipes')return recipesView();if(activeTab==='rules')return rulesView();if(activeTab==='builder')return builderView();if(activeTab==='engine')return engineView();if(activeTab==='history')return historyView();if(activeTab==='settings')return settingsView();return overviewView()}
function overviewView(){const rules=getRules();const hist=getHistory().slice(0,5);const st=stats();return `<section class="v952-split"><div class="v952-panel"><div class="v952-toolbar"><h2 class="v952-section-title">O que o motor está cuidando</h2><button class="v952-btn small" data-tab="engine">Simular evento</button></div><div class="v952-grid cols-2"><div class="v952-event-card"><b>Follow-up vencido</b><p class="v952-muted">Detecta retornos atrasados e coloca o lead em alerta.</p><button class="v952-btn small" data-emit="followup_overdue">Executar checagem</button></div><div class="v952-event-card"><b>Lead sem próxima ação</b><p class="v952-muted">Encontra leads soltos e cria próximo passo.</p><button class="v952-btn small" data-emit="lead_without_next_action">Executar checagem</button></div><div class="v952-event-card"><b>Lead parado</b><p class="v952-muted">Identifica oportunidade sem contato há muitos dias.</p><button class="v952-btn small" data-emit="lead_stuck">Executar checagem</button></div><div class="v952-event-card"><b>Proposta enviada</b><p class="v952-muted">Cria acompanhamento e sugere Playbook de proposta.</p><button class="v952-btn small" data-emit="pipeline_changed_to_proposal">Simular</button></div></div></div><div class="v952-panel"><div class="v952-toolbar"><h2 class="v952-section-title">Resumo</h2><span class="v952-pill ok">${VERSION}</span></div><div class="v952-mini-table"><div class="v952-mini-row"><b>Ativas</b><span>${st.active}</span><button class="v952-btn small" data-tab="rules">Ver</button></div><div class="v952-mini-row"><b>Pausadas</b><span>${st.paused}</span><button class="v952-btn small" data-tab="rules">Ver</button></div><div class="v952-mini-row"><b>Notificações</b><span>${st.notifications}</span><button class="v952-btn small" data-tab="history">Abrir</button></div></div><div class="v952-divider"></div><h3>Últimas execuções</h3>${hist.length?hist.map(logItem).join(''):'<div class="v952-empty">Ainda não há histórico.</div>'}</div></section>`}
function recipesView(){const rules=filteredRules();return `<section class="v952-panel"><div class="v952-toolbar"><div><h2 class="v952-section-title">Receitas prontas</h2><p class="v952-muted">Escolha uma receita, ative, teste ou edite como cópia. A lógica técnica fica escondida.</p></div><input class="v952-field v952-search" placeholder="Buscar automação..." value="${esc(searchTerm)}" data-search></div><div class="v952-subtabs">${CATS.map(c=>`<button class="v952-subtab ${activeCategory===c?'active':''}" data-cat="${c}">${c}</button>`).join('')}</div><div class="v952-grid cols-3">${rules.length?rules.map(recipeCard).join(''):'<div class="v952-empty">Nenhuma receita encontrada.</div>'}</div></section>`}
function recipeCard(r){return `<article class="v952-recipe" data-rule-card="${esc(r.id)}"><div class="v952-card-top"><div><div class="v952-card-title">${esc(r.name)}</div><div class="v952-card-desc">${esc(r.desc||'')}</div></div><span class="v952-pill ${r.active!==false?'ok':'warn'}">${r.active!==false?'Ativa':'Pausada'}</span></div><div class="v952-tags"><span class="v952-tag">${esc(r.category||'Contatar')}</span><span class="v952-tag">${esc(triggerLabels[r.trigger]||r.trigger)}</span></div><div class="v952-flow"><div class="v952-flow-line"><b>Quando</b><span>${esc(triggerLabels[r.trigger]||r.trigger)}</span></div><div class="v952-flow-line"><b>Se</b><span>${esc(asArray(r.conditions).length?asArray(r.conditions).map(c=>(fieldLabels[c.field]||c.field)+' '+c.op+' '+c.value).join(' + '):'sem condição extra')}</span></div><div class="v952-flow-line"><b>Fazer</b><span>${esc(asArray(r.actions).map(a=>actionLabels[a.type]||a.type).join(', '))}</span></div></div><div class="v952-preview">${esc(describeRule(r))}</div><div class="v952-actions"><button class="v952-btn small primary" data-toggle-rule="${esc(r.id)}">${r.active!==false?'Pausar':'Ativar'}</button><button class="v952-btn small" data-test-rule="${esc(r.id)}">Testar</button><button class="v952-btn small" data-run-rule="${esc(r.id)}">Executar agora</button><button class="v952-btn small" data-copy-rule="${esc(r.id)}">Editar como cópia</button></div></article>`}
function rulesView(){const rules=getRules();return `<section class="v952-panel"><div class="v952-toolbar"><div><h2 class="v952-section-title">Minhas automações</h2><p class="v952-muted">Regras salvas. Agora cada execução altera dados reais do lead e grava histórico.</p></div><button class="v952-btn primary" data-new-rule>Criar automação</button></div><div class="v952-grid cols-2">${rules.length?rules.map(ruleRow).join(''):'<div class="v952-empty">Nenhuma regra criada.</div>'}</div></section>`}
function ruleRow(r){return `<article class="v952-rule"><div class="v952-card-top"><div><div class="v952-card-title">${esc(r.name)}</div><div class="v952-card-desc">${esc(describeRule(r))}</div></div><span class="v952-pill ${r.active!==false?'ok':'warn'}">${r.active!==false?'Ativa':'Pausada'}</span></div><div class="v952-tags"><span class="v952-tag">${esc(r.category)}</span><span class="v952-tag">Rodou ${Number(r.runs||0)}x</span><span class="v952-tag">Impactou ${Number(r.affected||0)}</span></div><div class="v952-actions"><button class="v952-btn small" data-edit-rule="${esc(r.id)}">Editar</button><button class="v952-btn small" data-test-rule="${esc(r.id)}">Testar</button><button class="v952-btn small" data-run-rule="${esc(r.id)}">Executar agora</button><button class="v952-btn small" data-toggle-rule="${esc(r.id)}">${r.active!==false?'Pausar':'Ativar'}</button><button class="v952-btn small danger" data-delete-rule="${esc(r.id)}">Excluir</button></div></article>`}
function defaultDraft(){return {id:null,name:'',desc:'',category:'Contatar',active:true,trigger:'call_result_no_answer',conditions:[],actions:[{type:'create_followup_tomorrow',value:'Tentar novamente'}]}}
function builderView(){const d=builderDraft||defaultDraft();return `<section class="v952-builder"><aside class="v952-panel"><h2 class="v952-section-title">Construtor guiado</h2><p class="v952-muted">Monte uma regra como uma frase. O motor transforma isso em ações reais.</p><div class="v952-builder-steps"><div class="v952-step"><span class="v952-step-num">1</span><b>Quando acontecer</b></div><div class="v952-step"><span class="v952-step-num">2</span><b>Se tiver condição</b></div><div class="v952-step"><span class="v952-step-num">3</span><b>Fazer ações</b></div><div class="v952-step"><span class="v952-step-num">4</span><b>Testar e salvar</b></div></div><div class="v952-divider"></div><button class="v952-btn" data-reset-builder>Começar do zero</button></aside><main class="v952-panel"><div class="v952-grid cols-2"><label>Nome<input class="v952-field" data-b-name value="${esc(d.name)}" placeholder="Ex: Não atendeu → retorno amanhã"></label><label>Categoria<select class="v952-select" data-b-category>${CATS.filter(c=>c!=='Todos').map(c=>`<option ${d.category===c?'selected':''}>${c}</option>`).join('')}</select></label></div><label>Descrição<textarea class="v952-textarea" data-b-desc placeholder="Explique para que serve essa automação">${esc(d.desc||'')}</textarea></label><fieldset class="v952-fieldset"><legend>Quando isso acontecer</legend><select class="v952-select" data-b-trigger>${Object.keys(triggerLabels).map(k=>`<option value="${k}" ${d.trigger===k?'selected':''}>${triggerLabels[k]}</option>`).join('')}</select></fieldset><fieldset class="v952-fieldset"><legend>Condições</legend><div data-conditions>${asArray(d.conditions).map(conditionRow).join('')}</div><button class="v952-btn small" data-add-condition type="button">Adicionar condição</button></fieldset><fieldset class="v952-fieldset"><legend>Ações</legend><div data-actions>${asArray(d.actions).map(actionRow).join('')}</div><button class="v952-btn small" data-add-action type="button">Adicionar ação</button></fieldset><label class="v952-switch"><input type="checkbox" data-b-active ${d.active!==false?'checked':''}> Ativar após salvar</label><div class="v952-preview" data-builder-preview>${esc(describeRule(d))}</div><div class="v952-actions"><button class="v952-btn" data-builder-test>Testar</button><button class="v952-btn primary" data-builder-save>Salvar automação</button></div></main></section>`}
function conditionRow(c){c=c||{field:'origin',op:'contains',value:''};return `<div class="v952-row" data-cond-row><select class="v952-select" data-c-field>${Object.keys(fieldLabels).map(k=>`<option value="${k}" ${c.field===k?'selected':''}>${fieldLabels[k]}</option>`).join('')}</select><select class="v952-select" data-c-op>${['equals','not_equals','contains','not_contains','greater_than','less_than','exists','empty','is_true','is_false'].map(op=>`<option value="${op}" ${c.op===op?'selected':''}>${op}</option>`).join('')}</select><input class="v952-field" data-c-value value="${esc(c.value||'')}" placeholder="valor"><button class="v952-btn small danger" data-remove-row type="button">Remover</button></div>`}
function actionRow(a){a=a||{type:'create_followup_tomorrow',value:''};return `<div class="v952-action-row" data-action-row><select class="v952-select" data-a-type>${Object.keys(actionLabels).map(k=>`<option value="${k}" ${a.type===k?'selected':''}>${actionLabels[k]}</option>`).join('')}</select><input class="v952-field" data-a-value value="${esc(a.value||'')}" placeholder="valor/etapa/tag/texto"><button class="v952-btn small danger" data-remove-row type="button">Remover</button></div>`}
function engineView(){const q=readJSON(EVENT_QUEUE_KEY,[]).slice(0,8);return `<section class="v952-split"><div class="v952-panel"><h2 class="v952-section-title">Motor interno</h2><p class="v952-muted">Esta camada processa eventos do CRM. Quando uma aba dispara um evento, o motor encontra regras ativas, valida condições, executa ações e grava histórico.</p><div class="v952-grid"><div class="v952-preview">Evento → Regras compatíveis → Condições → Ações → Atualização do lead → Histórico</div><button class="v952-btn primary" data-run-checks>Rodar verificações automáticas agora</button><button class="v952-btn" data-undo-last>Desfazer última execução</button></div><div class="v952-divider"></div><h3>Simular evento</h3><div class="v952-row" style="grid-template-columns:1fr auto"><select class="v952-select" data-event-select>${Object.keys(triggerLabels).map(k=>`<option value="${k}">${triggerLabels[k]}</option>`).join('')}</select><button class="v952-btn" data-simulate-event>Executar evento</button></div></div><div class="v952-panel"><h2 class="v952-section-title">Eventos recentes</h2><div class="v952-history">${q.length?q.map(e=>`<div class="v952-log"><div class="v952-log-time">${esc(formatDate(e.at))}</div><div class="v952-log-main"><b>${esc(triggerLabels[e.eventType]||e.eventType)}</b><span>Evento capturado pelo motor V95.2</span></div><span class="v952-pill ok">fila</span></div>`).join(''):'<div class="v952-empty">Nenhum evento recente.</div>'}</div></div></section>`}
function historyView(){const h=getHistory();return `<section class="v952-panel"><div class="v952-toolbar"><div><h2 class="v952-section-title">Histórico do motor</h2><p class="v952-muted">Tudo que o motor testou, executou ou processou fica registrado aqui.</p></div><button class="v952-btn danger" data-clear-history>Limpar histórico</button></div><div class="v952-history">${h.length?h.map(logItem).join(''):'<div class="v952-empty">Ainda não há histórico.</div>'}</div></section>`}
function logItem(h){return `<div class="v952-log"><div class="v952-log-time">${esc(formatDate(h.at))}</div><div class="v952-log-main"><b>${esc(h.ruleName||triggerLabels[h.eventType]||h.kind||'Evento')}</b><span>${esc((h.kind||'registro')+' · '+(triggerLabels[h.eventType]||h.eventType||'manual')+' · '+Number(h.affected||0)+' lead(s) impactado(s)')}</span>${h.sample&&h.sample.length?'<span>'+esc(h.sample.join(', '))+'</span>':''}</div><span class="v952-pill ${h.kind==='test'?'warn':h.status==='undone'?'danger':'ok'}">${esc(h.kind||'log')}</span></div>`}
function settingsView(){const s=getSettings();return `<section class="v952-panel"><h2 class="v952-section-title">Configurações do motor</h2><p class="v952-muted">Controle quando o CRM deve rodar verificações e como tratar leads parados.</p><div class="v952-grid cols-2"><label class="v952-switch"><input type="checkbox" data-setting="enabled" ${s.enabled?'checked':''}> Motor de automações ativo</label><label class="v952-switch"><input type="checkbox" data-setting="autoRunOnOpen" ${s.autoRunOnOpen?'checked':''}> Verificar regras ao abrir o CRM</label><label>Limite de tentativas sem resposta<input class="v952-field" type="number" data-setting="noAnswerLimit" value="${esc(s.noAnswerLimit)}"></label><label>Dias para considerar lead parado<input class="v952-field" type="number" data-setting="stuckDays" value="${esc(s.stuckDays)}"></label><label>Horário do resumo diário<input class="v952-field" data-setting="dailySummaryHour" value="${esc(s.dailySummaryHour)}"></label></div><div class="v952-actions"><button class="v952-btn primary" data-save-settings>Salvar configurações</button><button class="v952-btn" data-reset-default-rules>Restaurar receitas padrão</button></div></section>`}
function formatDate(v){try{return new Date(v).toLocaleString('pt-BR',{day:'2-digit',month:'2-digit',hour:'2-digit',minute:'2-digit'})}catch(e){return v||''}}
function collectBuilder(){const root=$('#automacoes');if(!root)return builderDraft||defaultDraft();const d=builderDraft||defaultDraft();d.name=($('[data-b-name]',root)||{}).value||'';d.desc=($('[data-b-desc]',root)||{}).value||'';d.category=($('[data-b-category]',root)||{}).value||'Contatar';d.trigger=($('[data-b-trigger]',root)||{}).value||'manual_run';d.active=!!(($('[data-b-active]',root)||{}).checked);d.conditions=$$('[data-cond-row]',root).map(row=>({field:($('[data-c-field]',row)||{}).value,op:($('[data-c-op]',row)||{}).value,value:($('[data-c-value]',row)||{}).value}));d.actions=$$('[data-action-row]',root).map(row=>({type:($('[data-a-type]',row)||{}).value,value:($('[data-a-value]',row)||{}).value}));builderDraft=d;return d}
function saveBuilder(){const d=collectBuilder();if(!d.name.trim())d.name='Automação '+new Date().toLocaleDateString('pt-BR');if(!d.id)d.id=uid('rule');d.updatedAt=nowISO();const rules=getRules();const idx=rules.findIndex(r=>r.id===d.id);if(idx>=0)rules[idx]=d;else rules.unshift(d);saveRules(rules);builderDraft=null;activeTab='rules';render();toast('Automação salva',describeRule(d))}
function bindLocal(root){root.addEventListener('input',e=>{if(e.target.matches('[data-search]')){searchTerm=e.target.value;render()}else if(activeTab==='builder'){collectBuilder();const pv=$('[data-builder-preview]',root);if(pv)pv.textContent=describeRule(builderDraft)}});root.addEventListener('change',e=>{if(activeTab==='builder'){collectBuilder();const pv=$('[data-builder-preview]',root);if(pv)pv.textContent=describeRule(builderDraft)}});root.addEventListener('click',e=>{const t=e.target.closest('button,[data-tab],[data-cat]');if(!t)return;
 if(t.dataset.tab){activeTab=t.dataset.tab;render();return}
 if(t.dataset.cat){activeCategory=t.dataset.cat;render();return}
 if(t.hasAttribute('data-new-rule')){builderDraft=defaultDraft();activeTab='builder';render();return}
 if(t.hasAttribute('data-reset-builder')){builderDraft=defaultDraft();render();return}
 if(t.hasAttribute('data-add-condition')){collectBuilder();builderDraft.conditions.push({field:'origin',op:'contains',value:''});render();return}
 if(t.hasAttribute('data-add-action')){collectBuilder();builderDraft.actions.push({type:'create_followup_tomorrow',value:''});render();return}
 if(t.hasAttribute('data-remove-row')){t.closest('[data-cond-row],[data-action-row]').remove();collectBuilder();const pv=$('[data-builder-preview]',root);if(pv)pv.textContent=describeRule(builderDraft);return}
 const id=t.dataset.toggleRule||t.dataset.testRule||t.dataset.runRule||t.dataset.copyRule||t.dataset.editRule||t.dataset.deleteRule;
 if(id){handleRuleAction(t,id);return}
 if(t.hasAttribute('data-builder-save')){saveBuilder();return}
 if(t.hasAttribute('data-builder-test')){const d=collectBuilder();const res=testRule(d);toast('Teste concluído',res.affected+' lead(s) seriam impactados.');render();return}
 if(t.hasAttribute('data-run-checks')){runSystemChecks();toast('Verificações executadas');render();return}
 if(t.dataset.emit){const res=emit(t.dataset.emit,{});toast('Evento processado',res.rules+' regra(s), '+res.affected+' lead(s).');render();return}
 if(t.hasAttribute('data-simulate-event')){const val=($('[data-event-select]',root)||{}).value||'manual_run';const res=emit(val,{});toast('Evento simulado',res.rules+' regra(s), '+res.affected+' lead(s).');render();return}
 if(t.hasAttribute('data-undo-last')){undoLast();return}
 if(t.hasAttribute('data-clear-history')){writeJSON(HIST_KEY,[]);render();return}
 if(t.hasAttribute('data-save-settings')){saveSettingsFromScreen();render();return}
 if(t.hasAttribute('data-reset-default-rules')){saveRules(defaultRules());toast('Receitas padrão restauradas.');render();return}
});}
function handleRuleAction(btn,id){let rules=getRules();const r=rules.find(x=>x.id===id);if(!r)return;
 if(btn.dataset.toggleRule){r.active=r.active===false?true:false;saveRules(rules);toast(r.active?'Automação ativada':'Automação pausada');render();return}
 if(btn.dataset.testRule){const res=testRule(r);toast('Teste concluído',res.affected+' lead(s) seriam impactados.');render();return}
 if(btn.dataset.runRule){const res=runRule(r,r.trigger||'manual_run',{}, {force:true});toast('Automação executada',res.affected+' lead(s) impactado(s).');render();return}
 if(btn.dataset.copyRule){builderDraft=Object.assign({},r,{id:null,name:r.name+' — cópia'});activeTab='builder';render();return}
 if(btn.dataset.editRule){builderDraft=JSON.parse(JSON.stringify(r));activeTab='builder';render();return}
 if(btn.dataset.deleteRule){if(confirm('Excluir esta automação?')){saveRules(rules.filter(x=>x.id!==id));toast('Automação excluída.');render()}return}
}
function saveSettingsFromScreen(){const root=$('#automacoes');const s=getSettings();$$('[data-setting]',root).forEach(el=>{let v=el.type==='checkbox'?el.checked:el.value;if(el.type==='number')v=Number(v);s[el.dataset.setting]=v});saveSettings(s);toast('Configurações salvas.')}
function render(){const el=$('#automacoes');if(!el)return;D.body.classList.add('v952-automations-ready');el.className='view grid-view v952-automations-view';el.innerHTML=layout();bindLocal(el)}
function setOnlyView(id){$$('.view').forEach(v=>v.classList.toggle('active',v.id===id));$$('[data-view],[data-go],[data-go-view]').forEach(b=>{const v=b.getAttribute('data-view')||b.getAttribute('data-go')||b.getAttribute('data-go-view');if(v)b.classList.toggle('active',v===id)})}
function route(){setOnlyView('automacoes');const tt=$('#topbarTitle'),ts=$('#topbarSub');if(tt)tt.textContent='Automações';if(ts)ts.textContent='Motor de regras interno, receitas e histórico';render()}
function bindGlobal(){D.addEventListener('click',function(e){const nav=e.target.closest('[data-view="automacoes"],[data-go="automacoes"],[data-go-view="automacoes"]');if(nav){e.preventDefault();/* V97.1: removed e.stopImmediatePropagation() to avoid blocking button handlers */route();return}},true);
 D.addEventListener('click',function(e){const txt=lower((e.target.closest('button,a')||e.target).textContent||'');setTimeout(()=>{if(/não atendeu|nao atendeu/.test(txt))emit('call_result_no_answer',{});else if(/pediu retorno/.test(txt))emit('call_result_callback',{});else if(/atendeu|interessado/.test(txt))emit('call_result_answered',{});else if(/proposta/.test(txt)&&/enviar|enviada|mover/.test(txt))emit('pipeline_changed_to_proposal',{});else if(/fechado|ganho/.test(txt))emit('pipeline_won',{});else if(/perdido/.test(txt))emit('pipeline_lost',{})},120)},false);
 window.addEventListener('crm:automation:event',e=>{if(e.detail&&e.detail.type)emit(e.detail.type,e.detail.payload||{})});
 window.addEventListener('storage',e=>{if(LEAD_KEYS.includes(e.key))setTimeout(()=>emit('lead_updated',{}),160)});
}
const previousSetView=window.setView;
window.setView=function(view){if(String(view)==='automacoes'){route();return}if(typeof previousSetView==='function')return previousSetView.apply(this,arguments);setOnlyView(String(view))};
